"use strict";parserFactory.register("xiaxuenovels.xyz",()=>new XiaxuenovelsParser);class XiaxuenovelsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.sp-body a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.post-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".cb_p6_patreon_button, .jp-relatedposts, xiaxu-after-content"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h1.title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".entry-content")}}